#include <stdio.h>
#include <stdlib.h>

int g_init = 42;
int g_bss;

void show_text(void) {
    printf("text:  %p\n", (void *)show_text);
}

int main(void) {
    int local = 1;
    int *heap = ____((sizeof(int)));
    show_text();
    printf("data:  %p\n", (void *)&____);
    printf("bss:   %p\n", (void *)&____);
    printf("heap:  %p\n", (void *)heap);
    printf("stack: %p\n", (void *)&local);
    int order_ok = ((char *)show_text < (char *)&g_init)
                && ((char *)&g_init < (char *)&g_bss)
                && ((char *)&g_bss  < (char *)heap);
    printf("Order text<data<bss<heap: %s\n", order_ok ? "yes" : "no");
    free(heap);
    return 0;
}

